"use client";

import { useMemo } from 'react';
import { formatCurrency } from '@/lib/currencies';

// Simple Bar Chart Component
export function SpendBarChart({ data }: { data: { label: string, value: number, color?: string }[] }) {
    const maxValue = Math.max(...data.map(d => d.value));

    return (
        <div style={{ display: 'flex', alignItems: 'flex-end', gap: '1rem', height: '200px', paddingTop: '1rem' }}>
            {data.map((item, index) => (
                <div key={index} style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '0.5rem' }}>
                    <div
                        style={{
                            width: '100%',
                            height: `${(item.value / maxValue) * 100}%`,
                            backgroundColor: item.color || 'var(--accent)',
                            borderRadius: '4px 4px 0 0',
                            minHeight: '4px',
                            transition: 'height 0.5s ease-out',
                            position: 'relative'
                        }}
                        title={`${item.label}: ${formatCurrency(item.value, 'USD')}`}
                    >
                        {/* Tooltip on hover could go here */}
                    </div>
                    <span style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>{item.label}</span>
                </div>
            ))}
        </div>
    );
}

// Simple Donut Chart Component using SVG
export function BudgetDonutChart({ total, used }: { total: number, used: number }) {
    const radius = 40;
    const stroke = 8;
    const normalizedRadius = radius - stroke * 2;
    const circumference = normalizedRadius * 2 * Math.PI;
    const percent = Math.min((used / total) * 100, 100);
    const strokeDashoffset = circumference - (percent / 100) * circumference;

    // Determine color
    let color = 'var(--success)';
    if (percent > 80) color = '#eab308'; // Warning
    if (percent > 100) color = 'var(--error)';

    return (
        <div style={{ position: 'relative', width: '120px', height: '120px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <svg height="120" width="120" style={{ transform: 'rotate(-90deg)' }}>
                <circle
                    stroke="#e2e8f0"
                    strokeWidth={stroke}
                    fill="transparent"
                    r={normalizedRadius}
                    cx="60"
                    cy="60"
                />
                <circle
                    stroke={color}
                    strokeWidth={stroke}
                    strokeDasharray={circumference + ' ' + circumference}
                    style={{ strokeDashoffset, transition: 'stroke-dashoffset 0.5s ease-in-out' }}
                    strokeLinecap="round"
                    fill="transparent"
                    r={normalizedRadius}
                    cx="60"
                    cy="60"
                />
            </svg>
            <div style={{ position: 'absolute', textAlign: 'center' }}>
                <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>Used</div>
                <div style={{ fontWeight: 'bold', color: 'var(--text-main)' }}>{Math.round(percent)}%</div>
            </div>
        </div>
    );
}
